module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);
    parameter [1:0] ZERO = 2'b00;
    parameter [1:0] ONE = 2'b01;
    reg [1:0] i_state = ZERO;
    reg [1:0] i_next_state = ZERO;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i_state <= ZERO;
        end else begin
            case (i_state)
                ZERO: begin
                    if (a == 1'b1) begin
                        i_state <= ONE;
                        rise <= 1'b1;
                        down <= 1'b0;
                    end else begin
                        i_state <= ZERO;
                        rise <= 1'b0;
                        down <= 1'b0;
                    end
                end
                ONE: begin
                    if (a == 1'b0) begin
                        i_state <= ZERO;
                        rise <= 1'b0;
                        down <= 1'b1;
                    end else begin
                        i_state <= ONE;
                        rise <= 1'b0;
                        down <= 1'b0;
                    end
                end
            endcase
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i_next_state <= ZERO;
        end else begin
            case (i_next_state)
                ZERO: begin
                    if (a == 1'b1) begin
                        i_next_state <= ONE;
                    end else begin
                        i_next_state <= ZERO;
                    end
                end
                ONE: begin
                    if (a == 1'b0) begin
                        i_next_state <= ZERO;
                    end else begin
                        i_next_state <= ONE;
                    end
                end
            endcase
        end
    end
endmodule
